import datetime

def generate_113th_battalion_timeline():
    timeline = [
        {
            "date": datetime.date(1915, 12, 22),
            "event": "113th Battalion (Lethbridge Highlanders) authorized in Lethbridge, Alberta."
        },
        {
            "date": datetime.date(1915, None, None),
            "event": "Basic training begins on Lethbridge exhibition grounds; includes rifle training, grenade practice, and route marches."
        },
        {
            "date": datetime.date(1916, 5, None),
            "event": "Battalion moves to Sarcee Camp near Calgary for advanced training."
        },
        {
            "date": datetime.date(1916, None, None),
            "event": "Battalion paints battalion number using rocks on Signal Hill, Calgary."
        },
        {
            "date": datetime.date(1916, 9, 19),
            "event": "Orders received to entrain for the east; battalion travels to England."
        },
        {
            "date": datetime.date(1916, 9, 26),
            "event": "Embarks on SS Tuscania; crosses the Atlantic in 10 days."
        },
        {
            "date": datetime.date(1916, 10, 12),
            "event": "Most of the 113th Battalion arrives in France; 300 men are assigned as replacements to the 16th Battalion (Canadian Scottish)."
        },
        {
            "date": datetime.date(1917, 9, 1),
            "event": "113th Battalion officially disbanded."
        }
    ]
    return timeline

# Example usage:
timeline = generate_113th_battalion_timeline()
for entry in timeline:
    print(f"{entry['date']}: {entry['event']}")
